manifest_content:
{
  "name": "design-monorepo",
  "private": true,
  "workspaces": [
    "packages/*"
  ],
  "packageManager": "bun@1.3.9",
  "scripts": {
    "build": "turbo build",
    "test": "turbo test",
    "lint": "turbo lint",
    "cli": "bun run packages/cli/src/index.ts"
  },
  "devDependencies": {
    "@types/node": "^25.6.0",
    "bun-types": "^1.3.12",
    "turbo": "latest",
    "typescript": "latest"
  }
}

{
	"name": "flue",
	"type": "module",
	"private": true,
	"license": "Apache-2.0",
	"packageManager": "pnpm@11.1.1",
	"engines": {
		"node": ">=22",
		"pnpm": ">=11 <12"
	},
	"scripts": {
		"dev": "turbo dev",
		"build": "turbo build",
		"test": "turbo test",
		"test:integration": "pnpm --dir packages/cli run test:integration:cloudflare",
		"check": "turbo run build check:lint check:types && turbo run test",
		"check:lint": "biome lint . && knip",
		"check:knip": "knip",
		"check:types": "turbo run check:types --filter=!apps-www",
		"format": "turbo run format:lint format:style",
		"format:lint": "biome check . --write",
		"format:style": "prettier . --cache --write --list-different"
	},
	"devDependencies": {
		"@biomejs/biome": "^2.2.0",
		"@flue/runtime": "workspace:*",
		"@types/node": "^22.10.10",
		"bgproc": "^0.3.0",
		"knip": "^6.14.2",
		"prettier": "^3.4.2",
		"turbo": "^2.3.3",
		"typescript": "^6.0.3"
	},
	"dependencies": {
		"just-bash": "^3.0.1",
		"valibot": "^1.1.0"
	},
	"pnpm": {
		"overrides": {
			"typescript": "6.0.3"
		}
	}
}

{
  "name": "continue",
  "scripts": {
    "tsc:watch": "concurrently -n gui,vscode,core,binary -c cyan,magenta,yellow,green \"npm run tsc:watch:gui\" \"npm run tsc:watch:vscode\" \"npm run tsc:watch:core\" \"npm run tsc:watch:binary\"",
    "tsc:watch:gui": "tsc --project gui/tsconfig.json --watch --noEmit --pretty",
    "tsc:watch:vscode": "tsc --project extensions/vscode/tsconfig.json --watch --noEmit --pretty",
    "tsc:watch:core": "tsc --project core/tsconfig.json --watch --noEmit --pretty",
    "tsc:watch:binary": "tsc --project binary/tsconfig.json --watch --noEmit --pretty",
    "format": "prettier --write \"**/*.{js,jsx,ts,tsx,json,css,md}\" --ignore-path .gitignore --ignore-path .prettierignore",
    "format:check": "prettier --check \"**/*.{js,jsx,ts,tsx,json,css,md}\" --ignore-path .gitignore --ignore-path .prettierignore",
    "prepare": "husky"
  },
  "lint-staged": {
    "*.{js,jsx,ts,tsx,json,css,md}": "prettier --write"
  },
  "devDependencies": {
    "@typescript-eslint/parser": "^8.40.0",
    "concurrently": "^9.1.2",
    "eslint": "^8",
    "eslint-plugin-import": "^2.29.1",
    "husky": "^9.1.7",
    "lint-staged": "^15.5.2",
    "prettier": "^3.3.3",
    "prettier-plugin-tailwindcss": "^0.6.8",
    "typescript": "^5.6.3"
  },
  "dependencies": {
    "@ai-sdk/deepseek": "^2.0.20"
  }
}

[workspace]
resolver = "2"
members = [
  "crates",
  "crates/adapters/architect_ax",
  "crates/adapters/betfair",
  "crates/adapters/binance",
  "crates/adapters/bitmex",
  "crates/adapters/blockchain",
  "crates/adapters/bybit",
  "crates/adapters/coinbase",
  "crates/adapters/databento",
  "crates/adapters/deribit",
  "crates/adapters/derive",
  "crates/adapters/dydx",
  "crates/adapters/hyperliquid",
  "crates/adapters/interactive_brokers",
  "crates/adapters/kraken",
  "crates/adapters/lighter",
  "crates/adapters/okx",
  "crates/adapters/polymarket",
  "crates/adapters/sandbox",
  "crates/adapters/tardis",
  "crates/analysis",
  "crates/backtest",
  "crates/cli",
  "crates/common",
  "crates/core",
  "crates/cryptography",
  "crates/data",
  "crates/event_store",
  "crates/execution",
  "crates/indicators",
  "crates/infrastructure",
  "crates/live",
  "crates/model",
  "crates/network",
  "crates/persistence",
  "crates/persistence/macros",
  "crates/plugin",
  "crates/portfolio",
  "crates/pyo3",
  "crates/risk",
  "crates/serialization",
  "crates/system",
  "crates/testkit",
  "crates/trading",
  "examples/tutorials",
]

[workspace.package]
version = "0.59.0"
edition = "2024"
rust-version = "1.96.0"
authors = ["Nautech Systems <info@nautechsystems.io>"]
license = "LGPL-3.0-or-later"
readme = "README.md"
description = "Production-grade Rust-native trading engine with deterministic event-driven architecture"
categories = ["finance", "simulation", "asynchronous"]
keywords = [
  "finance",
  "trading",
  "trading-platform",
  "algorithmic-trading",
  "quantitative-finance",
]
documentation = "https://nautilustrader.io/docs"
repository = "https://github.com/nautechsystems/nautilus_trader"
homepage = "https://nautilustrader.io"

[workspace.dependencies]
nautilus-analysis = { path = "crates/analysis", version = "0.59.0" }
nautilus-backtest = { path = "crates/backtest", version = "0.59.0" }
nautilus-cli = { path = "crates/cli", version = "0.59.0" }
nautilus-common = { path = "crates/common", version = "0.59.0" }
nautilus-core = { path = "crates/core", version = "0.59.0" }
nautilus-cryptography = { path = "crates/cryptography", version = "0.59.0" }
nautilus-data = { path = "crates/data", version = "0.59.0" }
nautilus-execution = { path = "crates/execution", version = "0.59.0" }
nautilus-indicators = { path = "crates/indicators", version = "0.59.0" }
nautilus-infrastructure = { path = "crates/infrastructure", version = "0.59.0" }
nautilus-live = { path = "crates/live", version = "0.59.0", default-features = false }
nautilus-model = { path = "crates/model", version = "0.59.0" }
nautilus-network = { path = "crates/network", version = "0.59.0" }
nautilus-persistence = { path = "crates/persistence", version = "0.59.0" }
nautilus-persistence-macros = { path = "crates/persistence/macros", version = "0.59.0" }
nautilus-portfolio = { path = "crates/portfolio", version = "0.59.0" }
nautilus-pyo3 = { path = "crates/pyo3", version = "0.59.0" }
nautilus-risk = { path = "crates/risk", version = "0.59.0" }
nautilus-serialization = { path = "crates/serialization", version = "0.59.0" }
nautilus-system = { path = "crates/system", version = "0.59.0" }
nautilus-testkit = { path = "crates/testkit", version = "0.59.0" }
nautilus-trading = { path = "crates/trading", version = "0.59.0" }

# -----------------------------------------------------------------------------
# Adapters
#
# Note: default-features = false to control high-precision separately (not supported on Windows)
# -----------------------------------------------------------------------------
nautilus-architect-ax = { path = "crates/adapters/architect_ax", version = "0.59.0" }
nautilus-betfair = { path = "crates/adapters/betfair", version = "0.59.0", default-features = false }
nautilus-binance = { path = "crates/adapters/binance", version = "0.59.0", default-features = false }
nautilus-bitmex = { path = "crates/adapters/bitmex", version = "0.59.0", default-features = false }
nautilus-blockchain = { path = "crates/adapters/blockchain", version = "0.59.0" }
nautilus-bybit = { path = "crates/adapters/bybit", version = "0.59.0", default-features = false }
nautilus-coinbase = { path = "crates/adapters/coinbase", version = "0.59.0", default-features = false }
nautilus-databento = { path = "crates/adapters/databento", version = "0.59.0", default-features = false }
nautilus-deribit = { path = "crates/adapters/deribit", version = "0.59.0", default-features = false }
nautilus-derive = { path = "crates/adapters/derive", version = "0.59.0", default-features = false }
nautilus-dydx = { path = "crates/adapters/dydx", version = "0.59.0", default-features = false }
nautilus-hyperliquid = { path = "crates/adapters/hyperliquid", version = "0.59.0", default-features = false }
nautilus-interactive-brokers = { path = "crates/adapters/interactive_brokers", version = "0.59.0" }
nautilus-kraken = { path = "crates/adapters/kraken", version = "0.59.0", default-features = false }
nautilus-lighter
